375: func (rl *rateLimiter) ShouldSample(p tracesdk.SamplingParameters) tracesdk.SamplingResult {
376: 	rl.Lock()
377: 	defer rl.Unlock()
378: 	psc := trace.SpanContextFromContext(p.ParentContext)
379: 	if rl.balance >= 1 {
380: 		rl.balance -= 1
381: 		return tracesdk.SamplingResult{Decision: tracesdk.RecordAndSample, Tracestate: psc.TraceState()}
382: 	}
383: 	currentTime := rl.now()
384: 	elapsedTime := currentTime.Sub(rl.lastTick).Seconds()
385: 	rl.lastTick = currentTime
386: 	rl.balance = math.Min(rl.maxBalance, rl.balance+elapsedTime*rl.rps)
387: 	if rl.balance >= 1 {
388: 		rl.balance -= 1
389: 		return tracesdk.SamplingResult{Decision: tracesdk.RecordAndSample, Tracestate: psc.TraceState()}
390: 	}
391: 	return tracesdk.SamplingResult{Decision: tracesdk.Drop, Tracestate: psc.TraceState()}
392: }
